import{_ as e,o as a,c as o,a2 as l}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"李可老中医","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/02-李可老中医.md","filePath":"tcm-data/05-近现代/02-李可老中医.md","lastUpdated":1781084559000}'),r={name:"tcm-data/05-近现代/02-李可老中医.md"};function n(s,t,i,d,g,h){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="李可老中医" tabindex="-1">李可老中医 <a class="header-anchor" href="#李可老中医" aria-label="Permalink to &quot;李可老中医&quot;">​</a></h1><blockquote><p>李可（1930-2013年），山西灵石人 当代经方复兴的代表人物 代表著作：《李可老中医急危重症疑难病经验专辑》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名永福，字可</li><li><strong>生平</strong>：16岁参军，24岁被错划为右派，狱中自学中医</li><li><strong>师承</strong>：民间老中医温碧泉，后私淑彭子益、黄元御</li><li><strong>学术地位</strong>：当代中医急危重症的代表人物，&quot;<strong>中医ICU</strong>&quot;</li></ul><h3 id="李可的-中医人生" tabindex="-1">李可的&quot;中医人生&quot; <a class="header-anchor" href="#李可的-中医人生" aria-label="Permalink to &quot;李可的&quot;中医人生&quot;&quot;">​</a></h3><p>李可在狱中开始学医，出狱后在灵石县农村行医。因治愈大量被医院放弃的危重病人而声名鹊起。后遇见彭子益遗稿《圆运动的古中医学》，认为是中医复兴的希望，倾力整理出版。</p><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-阳气为本" tabindex="-1">1. 阳气为本 <a class="header-anchor" href="#_1-阳气为本" aria-label="Permalink to &quot;1. 阳气为本&quot;">​</a></h3><blockquote><p><strong>「人身之阳气，是生命的主宰。阳气一衰，百病丛生。」</strong></p></blockquote><p>继承黄元御&quot;阳尊阴卑&quot;、&quot;病于阳虚者，尽人皆是&quot;的思想。</p><h3 id="_2-凡病皆因温气不足" tabindex="-1">2. 凡病皆因温气不足 <a class="header-anchor" href="#_2-凡病皆因温气不足" aria-label="Permalink to &quot;2. 凡病皆因温气不足&quot;">​</a></h3><p>李可认为几乎所有慢性病、危重病的根源都在于<strong>阳气不足</strong>，尤其是脾肾之阳。</p><h3 id="_3-重用附子" tabindex="-1">3. 重用附子 <a class="header-anchor" href="#_3-重用附子" aria-label="Permalink to &quot;3. 重用附子&quot;">​</a></h3><p>李可的最大特色是<strong>大剂量使用附子</strong>：</p><ul><li>常规剂量：30-60g</li><li>危重症：100-200g</li><li>破格救心：最高用到<strong>500g</strong></li></ul><h3 id="_4-攻法与补法的结合" tabindex="-1">4. 攻法与补法的结合 <a class="header-anchor" href="#_4-攻法与补法的结合" aria-label="Permalink to &quot;4. 攻法与补法的结合&quot;">​</a></h3><p>李可不拘泥于&quot;虚则补之&quot;，对于痰湿瘀血等实邪，主张<strong>先攻后补</strong>或<strong>攻补兼施</strong>。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>破格救心汤</strong></td><td style="text-align:left;">附子30-200g、干姜60g、炙甘草60g、人参30g、山萸肉30-120g、龙牡磁各30g</td><td style="text-align:left;">心衰、休克</td></tr><tr><td style="text-align:left;"><strong>温氏奔豚汤</strong></td><td style="text-align:left;">附子、油桂、红参、沉香、砂仁、山药、茯苓、泽泻、牛膝、炙甘草</td><td style="text-align:left;">上热下寒</td></tr><tr><td style="text-align:left;"><strong>培元固本散</strong></td><td style="text-align:left;">人参、鹿茸、三七、琥珀、紫河车</td><td style="text-align:left;">慢病康复</td></tr><tr><td style="text-align:left;"><strong>乌头汤</strong></td><td style="text-align:left;">川乌、黄芪、麻黄、白芍、甘草、蜂蜜</td><td style="text-align:left;">类风湿</td></tr><tr><td style="text-align:left;"><strong>肾四味</strong></td><td style="text-align:left;">枸杞、菟丝子、补骨脂、淫羊藿</td><td style="text-align:left;">肾虚基础方</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「阳虚之人，十之八九；阴虚之人，百不见一。」</strong></p></blockquote><blockquote><p><strong>「凡见上热，必究其下寒。」</strong></p></blockquote><blockquote><p><strong>「破格用药，不是冒险，而是对病人生命负责。」</strong></p></blockquote><blockquote><p><strong>「千里马不遇伯乐，良医难逢明主。」</strong></p></blockquote><blockquote><p><strong>「中医治病，以阳气为本，以正气为根。」</strong></p></blockquote><hr><h2 id="五、对普光-普明处方的参考" tabindex="-1">五、对普光/普明处方的参考 <a class="header-anchor" href="#五、对普光-普明处方的参考" aria-label="Permalink to &quot;五、对普光/普明处方的参考&quot;">​</a></h2><p>您的处方&quot;温潜黄芽天魂汤&quot;中的<strong>附子9g</strong>用量参考了李可的思想但更为保守（李可用30g起步）。普明师嫂的处方未用附子，也是基于李可&quot;凡用附子，必先辨阳虚&quot;的原则。</p><hr><p><em>本条目为精简框架版。可扩展至李可医案选、附子用法专题、破格救心汤案例等。</em></p>',34)])])}const q=e(r,[["render",n]]);export{c as __pageData,q as default};
